def _databricks_ai_model_version_to_nested(
    databricks_ai_model_version: DatabricksAIModelVersion,
) -> DatabricksAIModelVersionNested:
    """Convert flat DatabricksAIModelVersion to nested format."""
    attrs = DatabricksAIModelVersionAttributes()
    _populate_databricks_ai_model_version_attrs(attrs, databricks_ai_model_version)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        databricks_ai_model_version,
        _DATABRICKS_AI_MODEL_VERSION_REL_FIELDS,
        DatabricksAIModelVersionRelationshipAttributes,
    )
    return DatabricksAIModelVersionNested(
        guid=databricks_ai_model_version.guid,
        type_name=databricks_ai_model_version.type_name,
        status=databricks_ai_model_version.status,
        version=databricks_ai_model_version.version,
        create_time=databricks_ai_model_version.create_time,
        update_time=databricks_ai_model_version.update_time,
        created_by=databricks_ai_model_version.created_by,
        updated_by=databricks_ai_model_version.updated_by,
        classifications=databricks_ai_model_version.classifications,
        classification_names=databricks_ai_model_version.classification_names,
        meanings=databricks_ai_model_version.meanings,
        labels=databricks_ai_model_version.labels,
        business_attributes=databricks_ai_model_version.business_attributes,
        custom_attributes=databricks_ai_model_version.custom_attributes,
        pending_tasks=databricks_ai_model_version.pending_tasks,
        proxy=databricks_ai_model_version.proxy,
        is_incomplete=databricks_ai_model_version.is_incomplete,
        provenance_type=databricks_ai_model_version.provenance_type,
        home_id=databricks_ai_model_version.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _databricks_ai_model_version_from_nested(
    nested: DatabricksAIModelVersionNested,
) -> DatabricksAIModelVersion:
    """Convert nested format to flat DatabricksAIModelVersion."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else DatabricksAIModelVersionAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DATABRICKS_AI_MODEL_VERSION_REL_FIELDS,
        DatabricksAIModelVersionRelationshipAttributes,
    )
    return DatabricksAIModelVersion(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_databricks_ai_model_version_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _databricks_ai_model_version_to_nested_bytes(
    databricks_ai_model_version: DatabricksAIModelVersion, serde: Serde
) -> bytes:
    """Convert flat DatabricksAIModelVersion to nested JSON bytes."""
    return serde.encode(
        _databricks_ai_model_version_to_nested(databricks_ai_model_version)
    )


def _databricks_ai_model_version_from_nested_bytes(
    data: bytes, serde: Serde
) -> DatabricksAIModelVersion:
    """Convert nested JSON bytes to flat DatabricksAIModelVersion."""
    nested = serde.decode(data, DatabricksAIModelVersionNested)
    return _databricks_ai_model_version_from_nested(nested)


